head.script:
/*
ozreport 출력 구현 안됨

TESTCASE : V200062874 20201101 ~ 20201201 
매출생성 테스트 케이스 V070014581
*/

scwin.vCurDate = WebSquare.date.getCurrentServerDate("yyyyMMdd");  // 서버를 기준으로 현재 날짜 반환
scwin.vQryStDt = scwin.vCurDate.substring(0, 6) + "01";  // 조회시작일자(현재 날짜가 포함된 달의 시작 일자)
scwin.vQryEndDt = scwin.vCurDate.substring(0, 6) + new Date(scwin.vCurDate.substring(0, 4), scwin.vCurDate.substring(4, 6) , 0).getDate();;  // 조회종료일자(현재 날짜가 포함된 달의 마지막 일자)


scwin.onpageload = function() {
    const codeOptions = [
        { grpCd: "OP194", compID: "lc_impExpDomesticClsCd,gr_master:impExpDomesticClsCd" }, // 수출입구분
        { grpCd: "SD070", compID: "gr_master:taxnClsCd" } // 과세구분

    ]
    $c.data.setCommonCode(codeOptions);
};

scwin.onUdcCompleted = function() {
    $p.setTimeout(function() {

        scwin.f_SetDefaultData();
        cbx_sumCheck.setValue("Y");
        ////임시
        /*
        ica_sellingDtSt.setValue("20201101");
        ica_sellingDtEnd.setValue("20201201");
        */
        ///임시
    }, {"delay":50});
};

//-------------------------------------------------------------------------
// Default Data Setting
//-------------------------------------------------------------------------
scwin.f_SetDefaultData = function () {
    ica_sellYmCreate.setValue(scwin.vCurDate.substr(0,6));
    ica_sellingDtSt.setValue(scwin.vQryStDt); // 공급일자시작
    ica_sellingDtEnd.setValue(scwin.vQryEndDt); // 공급일자종료		
}


scwin.f_termChk = async function (stObj, endObj) {
    if ( stObj.getValue().trim().length != 8 ) {
        //alert("매출기간은 필수입력 입니다.");
        stObj.focus();
        return true;
    }
    if ( endObj.getValue().trim().length != 8 ) {
        //alert("매출기간은  필수입력 입니다.");
        endObj.focus();
        return true;
    }

    if ( stObj.getValue().trim() > endObj.getValue().trim() ) {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_045, ['매출기간'] );	//기간 체크
        stObj.focus();
        return true;
    }
    return false;
}

//----------------------------------------------------------------------------
//   check function
//----------------------------------------------------------------------------  
scwin.fncCheckAll = function (isChecked) {
    var check = (isChecked == 1) ? "T":"";
    //gr_master.Redraw = false;
    var row;
    for (row = 0; row < ds_master.getRowCount() ; row++) {     
        ds_master.setCellData(row, "modCls", check);
    } 
    //gr_master.Redraw = true;
}

scwin.f_retrieve = async function () { 

    if ( await scwin.f_termChk(ica_sellingDtSt, ica_sellingDtEnd) &&  ica_sellYm.getValue().trim().length != 6 ) {
        await $c.win.alert("매출기간이나 매출년월을 입력해 주십시오.");
        return;	
    }

    ds_master.removeAll();
    ds_detail.removeAll();

    if (gr_master.getHeaderValue('modCls') == true) {
        gr_master.setHeaderValue('modCls',false);
        scwin.fncCheckAll(0); // uncheck
    }

    if (ica_sellingDtSt.getValue().trim().length == 8) {
        dma_condition1.set('sellingDtSt',ica_sellingDtSt.getValue());
    } else  {
        dma_condition1.set('sellingDtSt',"");
    }
    if (ica_sellingDtEnd.getValue().trim().length == 8) {
        dma_condition1.set('sellingDtEnd',ica_sellingDtEnd.getValue());
    } else {
        dma_condition1.set('sellingDtEnd',"");
    }
    dma_condition1.set('impExpDomesticClsCd',lc_impExpDomesticClsCd.getValue());
    dma_condition1.set('bilgClntNo',ed_bilgClntNo.getValue());	// 거래처
    dma_condition1.set('lineCd',ed_lineCd.getValue());	// line
    dma_condition1.set('vsslCd',ed_vsslCd.getValue());		// 모선
    dma_condition1.set('portcnt',ed_portcnt.getValue());	// 항차
    dma_condition1.set('bilgPicNo',ed_empNo.getValue());	// 청구담당자번호
    dma_condition1.set('certiNo',ed_certiNo.getValue());		// 거래명세서     
    dma_condition1.set('tempBarcdYn',lc_tempBarcdYn.getValue());	// 매출생성여부
    if (ica_sellYm.getValue().trim().length == 6) {
        dma_condition1.set('sellYm',ica_sellYm.getValue());
    } else  {
        dma_condition1.set('sellYm',"");
    }

    $c.sbm.execute(sbm_queryCondition1);
}

//-------------------------------------------------------------------------
// 팝업 버튼에 의한 팝업호출 여부 리턴
//-------------------------------------------------------------------------
scwin.f_isPopUpClicked = function () {
    /*
    if($c.gus.cfIsNull(event)) {
        return false;
    }
    var src = event.srcElement;
    return (src && src.tagName && (src.tagName.toUpperCase() == "IMG"));
    */
}

//-------------------------------------------------------------------------
// 사원팝업
//-------------------------------------------------------------------------
scwin.f_OpenEmpPopUp = function (code, name){
    //var aResult = new Array();	// 결과값을 담는 Array
    var sCode = ed_empNo.getValue();	// 사원 코드
    var sName = ed_empNm.getValue();	// 사원 명

    // 팝업을 띄운다. 
    udc_empNo.cfCommonPopUp(
        scwin.callbackEmpInfo, sCode, sName, "F", null, null, null, null, null, null, null, null, null, null, "F"
        );
    //$c.gus.cfSetReturnValue(aResult, code, name);	

}

//-------------------------------------------------------------------------
// 사원코드 입력창 OnChange Event
//-------------------------------------------------------------------------
scwin.f_EmpNoChanged = function (code, name){
    // 사원명 입력창을 지운다
    ed_empNm.setValue("");

    // 사원코드를 가져온다.
    var sCode = code.getValue().trim();

    if( sCode.length > 0){
        // 조회결과가 하나면 값을 리턴하고 아니면 조회창을 띄운다.
        udc_empNo.cfCommonPopUp(
            scwin.callbackEmpInfo, sCode, '', "T", null, null, null, null, null, null, null, null, null, null, "F"
            );
        //$c.gus.cfSetReturnValue(aResult, code, name);	
    }
}

//-------------------------------------------------------------------------
// Line 코드 검색 팝업창 띄우기
//-------------------------------------------------------------------------
scwin.f_openLinePopUp = function (pAllSearch) {
    var inObj = ed_lineCd;
    var pairObj = ed_lineNm;
    //var pAutoClose = scwin.f_getDefaultAutoClose();
    var pAutoClose = "F";
/*
    if(!scwin.f_canOpenPopUp(inObj, pairObj)) {
        //return;
    }
*/    
    //마스터 LINE 팝업
    udc_lineCd.cfCommonPopUp(
                    scwin.callbackLineInfo		// XML상의 SELECT ID	
                    ,$c.gus.cfGetValue(inObj)		// 화면에서의 ??? Code Element의	Value
                    ,$c.gus.cfGetValue(pairObj)	// 화면에서의 ??? Name Element의	Value
                    ,pAutoClose				// 결과가 1건 일때  원도우를	AutoClose 여부	(T:Close,F:Opened)
                    ,null					// 검색 결과	컬럼의 보여주는	개수 (SELECT절의 순서) MAX:10 - default (2)
                    ,null					// Title순서	
                    ,null					// 보여주는 각 컬럼들의 폭	
                    ,null					// 컬럼중에서 숨기는	컬럼 지정	
                    ,null					// SQL절의 WHERE절에	원하는 조건을 선택함 MAX:8개까지 가능
                    ,null					// POP-UP뛰을때 원도우의	사용자 정의	폭
                    ,null					// POP-UP뛰을때 우도우의	사용자 정의	높이	
                    ,null					// 윈도우 위치 Y좌표	
                    ,null					// 윈도우 위치 X좌표
                    ,null					// 중복체크여부	("F")
                    ,'F'				// 전체검색허용여부	("F")
                    ,"LINE,LINE코드,LINE명"				// POP-UP Window Title 검색어1,2	 ("Win타이틀,첫번검색Nm,두번?검색Nm")
                );

    //cfSetReturnValue(rtnList, inObj, pairObj);
}

//-------------------------------------------------------------------------
// 공통 Popup 처리 : Gubun Code 에 따른 공통 Popup 을 호출한다.
//-------------------------------------------------------------------------
scwin.f_openCommonPopUp = function (disGubun, pCode, pName, pClose, pAllSearch) {
    // 선언부
    var rtnList  = new Array();  // 공통POP-UP -> 요청화면 

    switch (disGubun) {

        case 2:  			
            //청구처코드팝업			
            udc_bilgClntNo.cfCommonPopUp(
                        scwin.callbackClntInfo,pCode.trim(),pName,pClose,null,null,null,null,null,null,null,null,null,null,pAllSearch,null
                        );	  			
            /*                                                    
            cfSetReturnValue(rtnList, ed_bilgClntNo, txt_bilgClntNm);  // 청구처코드, 청구처명
            if(rtnList != undefined){
                if ( rtnList[0] == '100002' || rtnList[0] == '100003' ) {
                    //특정거래명세유형 세팅
                    f_SetFmalPattern('B1');
                } else if(rtnList[0] == '100001'){
                    f_SetFmalPattern('A4');				
                }
            }
            */
            break;								 					

    }
}

//-------------------------------------------------------------------------
// 매출생성
//-------------------------------------------------------------------------
scwin.f_masterCreate = async function (){
    var flag = "";
    var row;

    if ( ica_sellYmCreate.getValue().trim().length != 6 ) {
        alert("매출년월은 필수입력 입니다.");
        ica_sellYmCreate.focus();
        return true;
    }	
    for (row = 0; row < ds_master.getRowCount() ; row++) { 
        if(ds_master.getCellData(row, "modCls") == "T"){
            if (ds_master.getCellData(row, "sellCreatYn") == "1" ) {
                alert("매출이 생성되어 있습니다.");
                ds_master.setRowPosition(row);
                gr_master.focus();
                return true;
            }	  				  		
            flag = "T";
        }
    }

    if ($c.gus.cfIsNull(flag)) {
        $c.win.alert("선택된 작업이 없습니다.");
        return;
    }	  	

    for (row = 0; row < ds_master.getRowCount() ; row++) { 
        //alert(ds_master.getCellData(row, "modCls"));
        if(ds_master.getCellData(row, "modCls") == "T"){
            ds_master.setCellData(row, "sellYm", ica_sellYmCreate.getValue());	  		
        }
    }

    var chkAlert = await $c.win.confirm("저장하시겠습니까?");
    if(chkAlert == true){ // 
        $c.sbm.execute(sbm_CreateMaster);
    }
}

//-------------------------------------------------------------------------
// 매출취소
//-------------------------------------------------------------------------
scwin.f_masterCancel = async function (){
    var flag = "";
    var row;

    for (row = 0; row < ds_master.getRowCount() ; row++) { 
        if(ds_master.getCellData(row, "modCls") == "T"){
            flag = "T";
            //ds_master.NameValue(row, "sellYm") = ed_sellYmCreate.Text;
            if (ds_master.getCellData(row, "sellCreatYn") == "0" ) {
                $c.win.alert("매출이 생성되어 있지 않습니다.");
                ds_master.setRowPosition(row);
                //gr_master.focus();
                return true;
            }	

        }
    }	  	
    if ($c.gus.cfIsNull(flag)) {
        $c.win.alert("선택된 작업이 없습니다.");
        return;
    }

    var chkAlert = await $c.win.confirm("저장하시겠습니까?");
    if(chkAlert == true){ // 저장하시겠습니까?         	 
        $c.sbm.execute(sbm_CancelMaster);
    }

}

//-------------------------------------------------------------------------
// 팝업 여부 체크
//-------------------------------------------------------------------------
scwin.f_canOpenPopUp = function (inObj, pairObj) {
    //cfCanOpenPopup
    //if (!f_isPopUpClicked()) {
        if($c.gus.cfIsNull(pairObj)) {
            if ($c.gus.cfGetValue(inObj) == "") {
                $c.gus.cfClearPairObj(inObj);
                $c.gus.cfSetHiddenValue(inObj,"");
                return false;
            }

            if ($c.gus.cfGetValue(inObj) == $c.gus.cfGetHiddenValue(inObj)) {
                return false;
            }
            return true;
        } else {
            if(!$c.gus.cfIsNull(event)) {
                if(!$c.gus.cfCanOpenPopup(pairObj, inObj)){ 
                    return false; 
                }
                $c.gus.cfClearPairObj(inObj);
            } else {
                if(!$c.gus.cfCanOpenPopup(inObj, pairObj)) {
                    return false; 
                }
                $c.gus.cfClearPairObj(pairObj);
            }
        }
    //}
    return true;
}

//-------------------------------------------------------------------------
// 인쇄 (거래명세서)
//-------------------------------------------------------------------------
