                ds_master.setRowPosition(i);
                return; 	  				
            }
        }
    }

    var printCnt = 0;
    var ozMode = "";
    //OZStartBatch();

    for(var i=0; i < ds_master.getRowCount(); i++){
        if(ds_master.getCellData(i, "modCls") == "T") {
