            odiParam.add("spplyFg", lc_spplyFg.getValue());
            if(cbx_sumCheck.getValue() == "Y"){
                odiParam.add("sumGbn", "Y");
            }else{
                odiParam.add("sumGbn", "N");
            }
            */
