                    useprogressbar: false, // 프로그레스바 쓸지 말지
                    zoom: 100, // 배율 설정
                    mode: ozMode,
                    //mode: "preview",
                    copies : 1
                },
                formParam: {

                }
            };

            let opts = {
                id: "ozReportPopup",
                popupName: "오즈 리포트",
                modal: true,
                type: "browserPopup",
                width: 1000,
