                title: "오즈 리포트"
            };
            await $c.win.openPopup("/ui/cm/zz/ozreportPopup.xml", opts, data);

            printCnt++;
        }
    }
    console.log(printCnt);
    if(printCnt == 0){
        $c.gus.cfAlertMsg(MSG_CM_WRN_007,["발행할 거래명세서"]);
