scwin.callbackLineInfo = function (rtnList) {
    var inObj = ed_lineCd;
    var pairObj = ed_lineNm;

    $c.gus.cfSetReturnValue(rtnList, inObj, pairObj);
}

scwin.callbackClntInfo = function (rtnList) {
    $c.gus.cfSetReturnValue(rtnList, ed_bilgClntNo, ed_bilgClntNm);  // 청구처코드, 청구처명
    if(rtnList != undefined && rtnList != null){
        if ( rtnList[0] == '100002' || rtnList[0] == '100003' ) {
            //특정거래명세유형 세팅
            scwin.f_SetFmalPattern('B1');
        } else if(rtnList[0] == '100001'){
            scwin.f_SetFmalPattern('A4');				
        }
    }
}

scwin.callbackEmpInfo = function (rtnList) {
    var code = ed_empNo;
    var name = ed_empNm;
    $c.gus.cfSetReturnValue(rtnList, code, name);	
}

