scwin.gr_master_oncellclick = function (rowIndex, columnIndex, columnId) {

    // 해당 기능은 gr_master_oncellindexchange 의 oldRow < 0 안으로 이관
    /*
    dma_condition2.set("certiNo" , ds_master.getCellData(rowIndex , "certiNo"));
    $c.sbm.execute(sbm_queryCondition2);
    */

    var colid = ds_master.getColumnID(columnIndex);

    if(colid == "modCls" && ds_master.getCellData(rowIndex, "modCls") == 0) {
        ds_master.undoRow(rowIndex);
    }
};

scwin.gr_master_oncellindexchange = function (rowIndex, columnIndex, oldRow, oldColumnIndex) {
    //if(columnIndex != 0){
        if(oldRow < 0){
            dma_condition2.set("certiNo" , ds_master.getCellData(rowIndex , "certiNo"));
            $c.sbm.execute(sbm_queryCondition2);
        } else {
            if (ds_detail.getCellData(0,"certiNo") != ds_master.getCellData(rowIndex,"certiNo")) {
                dma_condition2.set("certiNo" , ds_master.getCellData(rowIndex , "certiNo"));
                $c.sbm.execute(sbm_queryCondition2);
            }
        }
    //}

};

