scwin.sbm_queryCondition1_submitdone = function (e) {
    scwin.ds_master_ondataload();
};

scwin.sbm_queryCondition2_submitdone = function (e) {
    spa_cnt2.setValue(ds_detail.getRowCount());
};

scwin.sbm_CreateMaster_submitdone =  async function (e) {
    console.log(e.responseJSON.resultDataSet);
    if(e.responseJSON.resultDataSet[0].Code == 0) {
        await $c.win.alert(MSG_CM_INF_001);
        scwin.f_retrieve();
    }
};

scwin.sbm_CancelMaster_submitdone =  async function (e) {
    console.log(e.responseJSON.resultDataSet);
    if(e.responseJSON.resultDataSet[0].Code == 0) {
        await $c.win.alert(MSG_CM_INF_001);
        scwin.f_retrieve();
    }
};

scwin.ds_master_ondataload = function () {

    // 총 조회건수 표시
    if (ds_master.getRowCount() == 0) {
        $c.win.alert("조회결과가 존재하지 않습니다.");
        return;
    } else {
        dma_condition2.set("certiNo" , ds_master.getCellData(0,"certiNo"));
        $c.sbm.execute(sbm_queryCondition2);
    }
    spa_cnt1.setValue(ds_master.getRowCount());
};

/////////////////////////////////////////////////////////
//////////////// Submission EVENT END  //////////////////
/////////////////////////////////////////////////////////

