scwin.onkeyup = function (e) {
    this.setValue(e.target.value.toUpperCase());
};


scwin.excelDown1 = function () {

    const options = {
        fileName : "매출목록.xlsx", //[default : excel.xlsx] options.fileName 값이 없을 경우 default값 세팅
        sheetName : "매출목록",
        startRowIndex : 2,
        startColumnIndex : 0,
    };

    // 타이틀
    const infoArr = [{
                    rowIndex : 0, colIndex : 0, rowSpan : 1, colSpan : 9, text : "매출목록", textAlign : "center", 
                    drawBorder : false, fontSize : "18px", bodyWordwrap: true
                }]


    $c.data.downloadGridViewExcel(gr_master, options, infoArr);
}

